const key = $json.sessionKey;
const stored = $getWorkflowStaticData('global');
const raw = stored[key];
let history = [];

try {
  history = raw ? JSON.parse(raw) : [];
  if (!Array.isArray(history)) history = [];
} catch (e) {
  history = [];
}

const MAX_MESSAGES = 20;
const MAX_CHARS = 8000;

if (history.length > MAX_MESSAGES) history = history.slice(-MAX_MESSAGES);

let totalChars = history.reduce((sum, m) => sum + (m.content?.length || 0), 0);
while (totalChars > MAX_CHARS && history.length > 2) {
  const removed = history.shift();
  totalChars -= (removed.content?.length || 0);
}

return [{ json: { ...$json, history } }];

const { question, history } = $json;

const hebrewChars = (question.match(/[\u0590-\u05FF\uFB1D-\uFB4F]/g) || []).length;
const cyrillicChars = (question.match(/[\u0400-\u04FF]/g) || []).length;
const latinChars = (question.match(/[a-zA-Z]/g) || []).length;
const total = hebrewChars + cyrillicChars + latinChars || 1;
const cleanLen = question.replace(/\s/g, '').length;

let detectedLang = 'en';
if (hebrewChars / total > 0.3) detectedLang = 'he';
else if (cyrillicChars / total > 0.3) detectedLang = 'ru';

if (cleanLen < 8 && history?.length) {
  const recentText = history.slice(-6).map(m => m.content || '').join(' ');
  const hHe = (recentText.match(/[\u0590-\u05FF]/g) || []).length;
  const hRu = (recentText.match(/[\u0400-\u04FF]/g) || []).length;
  const hEn = (recentText.match(/[a-zA-Z]/g) || []).length;
  if (hHe > hRu && hHe > hEn) detectedLang = 'he';
  else if (hRu > hHe && hRu > hEn) detectedLang = 'ru';
}

return [{ json: { ...$json, detectedLang } }];

const { question, history, detectedLang } = $json;

const q = question.trim();
const lower = q.toLowerCase();

const lastAssistant = [...(history || [])].reverse().find(m => m.role === 'assistant')?.content || '';
const recent = [...(history || [])].slice(-10).map(m => m.content || '').join(' ');
const context = `${lastAssistant} ${recent}`.replace(/\s+/g, ' ').trim();

function includesAny(text, arr) {
  return arr.some(x => text.includes(x));
}

const cleanLen = q.replace(/\s/g, '').length;
const isShortFollowUp = cleanLen <= 22 && (history || []).length > 0;

const ctxLower = context.toLowerCase();

const isHebrew = detectedLang === 'he';
const currentYear = new Date().getFullYear();

// broad intents
const isSports = /ספורט|כדורגל|כדורסל|משחק|תוצאה|כבש|שער|טבלה|ליגה|אליפות|מלך\s*שערים|מכבי|הפועל|score|scored|match|standings|league|football|basketball/i.test(q + ' ' + context);
const isPolitics = /בחירות|כנסת|ממשלה|ראש\s*ממשלה|נשיא|שרים|קואליציה|אופוזיציה|election|knesset|government|prime minister|president/i.test(q);
const isWeather = /מזג\s*אוויר|טמפרטורה|גשם|חם|קר|תחזית|weather|forecast|temperature|rain/i.test(q);
const isFinance = /דולר|אירו|שקל|שער|בורסה|מניה|ביטקוין|קריפטו|מחיר|exchange rate|stock|price|bitcoin|crypto|usd|eur/i.test(q);
const isNews = /חדשות|מה\s*קרה|היום|עכשיו|עדכני|אחרון|latest|news|today|current|now/i.test(q);
const isPerson = /מי\s+זה|מי\s+זו|בת\s*כמה|בן\s*כמה|מה\s*אמר|מה\s*עשתה|who is|age of|what did/i.test(q);
const isTravel = /טיסה|מלון|מסעדה|טיול|חופשה|לאן|אטרקציות|flight|hotel|restaurant|travel|trip|attractions/i.test(q);
const isTech = /איך\s*לתקן|קוד|שגיאה|api|docker|n8n|javascript|python|server|bug|error|code/i.test(q);
const isHistoryFact = /מתי\s*היה|באיזה\s*שנה|מי\s*היה|היסטוריה|פעם\s*אחרונה|when was|what year|history|last time/i.test(q);

const needsSearch =
  isShortFollowUp ||
  isSports ||
  isPolitics ||
  isWeather ||
  isFinance ||
  isNews ||
  isPerson ||
  isTravel ||
  isHistoryFact;

// Specific sub-intents
const isAllTimeQuestion = /כל\s*הזמנים|בכל\s*הזמנים|היסטוריה|אי\s*פעם|all[\s-]?time|history|ever/i.test(q);
const isTopScorerQuestion = /מלך\s*שערים|מלך\s*השערים|top scorer|goalscorer/i.test(q);

let intent = 'general';
if (isSports) intent = 'sports';
else if (isPolitics) intent = 'politics';
else if (isWeather) intent = 'weather';
else if (isFinance) intent = 'finance';
else if (isNews) intent = 'news';
else if (isPerson) intent = 'person';
else if (isTravel) intent = 'travel';
else if (isTech) intent = 'tech';
else if (isHistoryFact) intent = 'history_fact';

let queries = [];

if (isShortFollowUp && context) {
  // Follow-up: combine previous subject with current question.
  queries = [
    `${context} ${q}`.slice(-280),
    `${q} ${context}`.slice(-280),
    isHebrew ? `${q} ${currentYear}` : `${q} ${currentYear}`
  ];
} else if (intent === 'sports') {
  if (isAllTimeQuestion && isTopScorerQuestion && /מכבי\s*חיפה|maccabi haifa/i.test(q + ' ' + context)) {
    queries = [
      'מכבי חיפה מלך השערים בכל הזמנים',
      'מכבי חיפה שיאני כיבושים כל הזמנים',
      'Maccabi Haifa all time top scorer'
    ];
  } else {
    queries = [
      `${q} ${currentYear}`,
      `${q} תוצאה טבלה כובשים ${currentYear}`,
      `${q} latest result standings scorers ${currentYear}`
    ];
  }
} else if (intent === 'politics') {
  queries = [
    `${q}`,
    `${q} תאריך רשמי`,
    `${q} official date`
  ];

  if (/בחירות|election/i.test(q)) {
    queries = [
      'הבחירות האחרונות בישראל מתי היו',
      'בחירות לכנסת האחרונה תאריך',
      'Israel last election date'
    ];
  }
} else if (intent === 'weather') {
  queries = [
    `${q} תחזית מזג אוויר`,
    `${q} weather forecast`,
    `${q} temperature today`
  ];
} else if (intent === 'finance') {
  queries = [
    `${q} שער עדכני`,
    `${q} מחיר עכשיו`,
    `${q} current price exchange rate`
  ];
} else if (intent === 'news') {
  queries = [
    `${q} ${currentYear}`,
    `${q} חדשות עדכניות`,
    `${q} latest news`
  ];
} else if (intent === 'person') {
  queries = [
    `${q}`,
    `${q} biography latest`,
    `${q} ויקיפדיה`
  ];
} else if (intent === 'travel') {
  queries = [
    `${q} ${currentYear}`,
    `${q} המלצות עדכניות`,
    `${q} reviews guide`
  ];
} else if (intent === 'history_fact') {
  queries = [
    `${q}`,
    `${q} תאריך`,
    `${q} official`
  ];
} else {
  // General fallback: always search, because this is a WhatsApp assistant expected to know many domains.
  queries = [
    `${q}`,
    `${q} ${currentYear}`,
    isHebrew ? `${q} מידע` : `${q} information`
  ];
}

queries = [...new Set(
  queries
    .map(x => x.replace(/\s+/g, ' ').trim())
    .filter(Boolean)
)].slice(0, 3);

return [{
  json: {
    ...$json,
    searchQuery1: queries[0] || q,
    searchQuery2: queries[1] || queries[0] || q,
    searchQuery3: queries[2] || queries[1] || queries[0] || q,
    searchQueries: queries,
    shouldSearch: true,
    intentDebug: {
      intent,
      needsSearch,
      isShortFollowUp,
      isSports,
      isPolitics,
      isWeather,
      isFinance,
      isNews,
      isPerson,
      isTravel,
      isTech,
      isHistoryFact,
      isAllTimeQuestion,
      isTopScorerQuestion
    }
  }
}];

const prev = $('Build Search Query').first().json;

function getResultsFromNode(nodeName) {
  try {
    const item = $(nodeName).first().json || {};
    const results = Array.isArray(item.results) ? item.results : [];
    return results;
  } catch (e) {
    return [];
  }
}

const allResults = [
  ...getResultsFromNode('Search SearXNG 1').map(r => ({...r, _query: prev.searchQuery1})),
  ...getResultsFromNode('Search SearXNG 2').map(r => ({...r, _query: prev.searchQuery2})),
  ...getResultsFromNode('Search SearXNG 3').map(r => ({...r, _query: prev.searchQuery3}))
];

const seen = new Set();
const results = [];
for (const r of allResults) {
  const key = (r.url || r.title || '').toLowerCase();
  if (!key || seen.has(key)) continue;
  seen.add(key);
  results.push(r);
  if (results.length >= 12) break;
}

const formattedResults = results.map((r, i) => {
  const title = r.title || '';
  const url = r.url || '';
  const content = r.content || r.snippet || '';
  const query = r._query || '';
  return `${i + 1}. Query: ${query}\nTitle: ${title}\nSnippet: ${content}\nURL: ${url}`;
}).join('\n\n');

const now = new Date();
const israelTime = now.toLocaleString(
  prev.detectedLang === 'he' ? 'he-IL' : prev.detectedLang === 'ru' ? 'ru-RU' : 'en-US',
  { timeZone: 'Asia/Jerusalem', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' }
);

const langLabel = prev.detectedLang === 'he' ? 'Hebrew' : prev.detectedLang === 'ru' ? 'Russian' : 'English';

let historyBlock = '';
if (prev.history?.length) {
  historyBlock = '\nConversation so far:\n';
  for (const msg of prev.history) {
    historyBlock += `${msg.role === 'user' ? 'User' : 'Assistant'}: ${msg.content}\n`;
  }
}

const systemMessage = `You are a general-purpose smart WhatsApp assistant. Reply ONLY in ${langLabel}.
Today: ${israelTime}. User: ${prev.senderName}.

You receive web search results from SearXNG for every user question.
Your job:
- Answer using the search results when they are relevant.
- For current facts, politics, sports, weather, prices, people, news, schedules, laws, and recent info: rely on search results, not memory.
- For stable/general questions, you may combine basic reasoning with search results.
- For follow-up questions, use the conversation history to understand what "it", "he", "there", "next", "who", etc. refers to.

Important interpretation rules:
- "בכל הזמנים", "כל הזמנים", "היסטוריה", "אי פעם" means all-time / historical record.
- "פעם אחרונה" usually means the most recent occurrence.
- "מתי" asks for date/time.
- "מי" asks for a person/name.
- "באיזה מקום" asks for ranking/position.

Answer rules:
- If the exact answer appears in results, answer directly and briefly.
- If the results are insufficient, say you could not find precise information. Do not guess.
- If results disagree, mention uncertainty briefly.
- Keep the answer natural like WhatsApp.
- No preamble. No citations/URLs unless the user asks.
- No emojis unless the user used emojis first.`;

const prompt = `${historyBlock}

User question: ${prev.question}

Detected intent:
${JSON.stringify(prev.intentDebug || {}, null, 2)}

Search queries used:
1. ${prev.searchQuery1}
2. ${prev.searchQuery2}
3. ${prev.searchQuery3}

Web search results:
${formattedResults || 'No useful search results returned.'}

Answer the user now.`;

return [{
  json: {
    ...prev,
    systemMessage,
    prompt,
    searchResultsCount: results.length
  }
}];

