let provider = 'ai-agent';

try {
  answer = ($json.output || $json.text || '').trim();
} catch (e) {
  answer = '';
  provider = 'error';
}

function stripThinking(text) {
  if (!text) return '';
  let t = text;
  t = t.replace(/<think[^>]*>[\s\S]*?<\/think>/gi, '');
  t = t.replace(/<reasoning[^>]*>[\s\S]*?<\/reasoning>/gi, '');
  t = t.replace(/<analysis[^>]*>[\s\S]*?<\/analysis>/gi, '');
  t = t.replace(/<scratchpad[^>]*>[\s\S]*?<\/scratchpad>/gi, '');
  t = t.replace(/<\|[^|>]*\|>/g, '');
  t = t.replace(/\n{3,}/g, '\n\n').trim();
  return t;
}

answer = stripThinking(answer);

const leakPatterns = [
  /you are a.*assistant/i,
  /system message/i,
  /web search results/i,
  /search query used/i,
  /conversation so far/i
];

const isLeak = leakPatterns.some(p => p.test(answer));
const lang = prev.detectedLang || 'en';

if (!answer || answer.length < 2 || isLeak) {
  answer = lang === 'he'
    ? 'לא מצאתי מידע מדויק.'
    : lang === 'ru'
      ? 'Не нашёл точной информации.'
      : 'I could not find precise information.';
  provider = 'error';
}

const key = prev.sessionKey;
const stored = $getWorkflowStaticData('global');
let history = [];

try {
  history = stored[key] ? JSON.parse(stored[key]) : [];
  if (!Array.isArray(history)) history = [];
} catch (e) {
  history = [];
}

if (provider !== 'error') {
  history.push({ role: 'user', content: prev.question });
  history.push({ role: 'assistant', content: answer });
  if (history.length > 20) history = history.slice(-20);
  stored[key] = JSON.stringify(history);
}

return [{
  json: {
    chatId: prev.chatId,
    answer,
    provider,
    searchQuery: prev.searchQuery,
    searchResultsCount: prev.searchResultsCount
  }
}];

