  } catch (e) {
    return [];
  }
}

const allResults = [
  ...getResultsFromNode('Search SearXNG 1').map(r => ({...r, _query: prev.searchQuery1})),
  ...getResultsFromNode('Search SearXNG 2').map(r => ({...r, _query: prev.searchQuery2})),
  ...getResultsFromNode('Search SearXNG 3').map(r => ({...r, _query: prev.searchQuery3}))
];

const seen = new Set();
const results = [];
for (const r of allResults) {
  const key = (r.url || r.title || '').toLowerCase();
  if (!key || seen.has(key)) continue;
  seen.add(key);
  results.push(r);
  if (results.length >= 12) break;
}

const formattedResults = results.map((r, i) => {
  const title = r.title || '';
  const url = r.url || '';
  const content = r.content || r.snippet || '';
  const query = r._query || '';
  return `${i + 1}. Query: ${query}\nTitle: ${title}\nSnippet: ${content}\nURL: ${url}`;
}).join('\n\n');

const now = new Date();
const israelTime = now.toLocaleString(
  prev.detectedLang === 'he' ? 'he-IL' : prev.detectedLang === 'ru' ? 'ru-RU' : 'en-US',
  { timeZone: 'Asia/Jerusalem', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' }
);

const langLabel = prev.detectedLang === 'he' ? 'Hebrew' : prev.detectedLang === 'ru' ? 'Russian' : 'English';

let historyBlock = '';
if (prev.history?.length) {
  historyBlock = '\nConversation so far:\n';
  for (const msg of prev.history) {
    historyBlock += `${msg.role === 'user' ? 'User' : 'Assistant'}: ${msg.content}\n`;
  }
}

const systemMessage = `You are a general-purpose smart WhatsApp assistant. Reply ONLY in ${langLabel}.
Today: ${israelTime}. User: ${prev.senderName}.

You receive web search results from SearXNG for every user question.
Your job:
- Answer using the search results when they are relevant.
- For current facts, politics, sports, weather, prices, people, news, schedules, laws, and recent info: rely on search results, not memory.
- For stable/general questions, you may combine basic reasoning with search results.
- For follow-up questions, use the conversation history to understand what "it", "he", "there", "next", "who", etc. refers to.

Important interpretation rules:
- "בכל הזמנים", "כל הזמנים", "היסטוריה", "אי פעם" means all-time / historical record.
- "פעם אחרונה" usually means the most recent occurrence.
- "מתי" asks for date/time.
- "מי" asks for a person/name.
- "באיזה מקום" asks for ranking/position.

Answer rules:
- If the exact answer appears in results, answer directly and briefly.
- If the results are insufficient, say you could not find precise information. Do not guess.
- If results disagree, mention uncertainty briefly.
- Keep the answer natural like WhatsApp.
- No preamble. No citations/URLs unless the user asks.
- No emojis unless the user used emojis first.`;

const prompt = `${historyBlock}

User question: ${prev.question}

Detected intent:
${JSON.stringify(prev.intentDebug || {}, null, 2)}

Search queries used:
1. ${prev.searchQuery1}
2. ${prev.searchQuery2}
3. ${prev.searchQuery3}

Web search results:
${formattedResults || 'No useful search results returned.'}

Answer the user now.`;

return [{
  json: {
    ...prev,
    systemMessage,
    prompt,
    searchResultsCount: results.length
  }
}];

const prev = $('Build AI Prompt').first().json;

let answer = '';
let provider = 'ai-agent';

try {
  answer = ($json.output || $json.text || '').trim();
} catch (e) {
  answer = '';
  provider = 'error';
}

function stripThinking(text) {
  if (!text) return '';
  let t = text;
  t = t.replace(/<think[^>]*>[\s\S]*?<\/think>/gi, '');
  t = t.replace(/<reasoning[^>]*>[\s\S]*?<\/reasoning>/gi, '');
  t = t.replace(/<analysis[^>]*>[\s\S]*?<\/analysis>/gi, '');
  t = t.replace(/<scratchpad[^>]*>[\s\S]*?<\/scratchpad>/gi, '');
  t = t.replace(/<\|[^|>]*\|>/g, '');
  t = t.replace(/\n{3,}/g, '\n\n').trim();
  return t;
}

answer = stripThinking(answer);

const leakPatterns = [
  /you are a.*assistant/i,
  /system message/i,
  /web search results/i,
  /search query used/i,
  /conversation so far/i
];

const isLeak = leakPatterns.some(p => p.test(answer));
const lang = prev.detectedLang || 'en';

if (!answer || answer.length < 2 || isLeak) {
  answer = lang === 'he'
    ? 'לא מצאתי מידע מדויק.'
    : lang === 'ru'
      ? 'Не нашёл точной информации.'
      : 'I could not find precise information.';
  provider = 'error';
}

const key = prev.sessionKey;
const stored = $getWorkflowStaticData('global');
let history = [];

try {
  history = stored[key] ? JSON.parse(stored[key]) : [];
  if (!Array.isArray(history)) history = [];
} catch (e) {
  history = [];
}

if (provider !== 'error') {
  history.push({ role: 'user', content: prev.question });
  history.push({ role: 'assistant', content: answer });
  if (history.length > 20) history = history.slice(-20);
  stored[key] = JSON.stringify(history);
}

return [{
  json: {
    chatId: prev.chatId,
    answer,
    provider,
    searchQuery: prev.searchQuery,
    searchResultsCount: prev.searchResultsCount
  }
}];
